using System.Collections;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Overlay de imagem em ecrã inteiro (Sistema de Pistas/Rumores —
/// Action_ShowFullscreenImage e reabertura de Pistas/Rumores a partir do
/// Diário).
///
/// Mostra uma imagem (com título/descrição opcionais) por cima de tudo, com o
/// fundo escurecido, e pausa o jogo (GamePauseUtil) enquanto estiver aberto.
/// Fecha com o botão normal de Confirmar/Interagir (teclado OU comando —
/// PlayerInputRouter.InteractPressed, tal como NpcDialogueBalloon).
///
/// NÃO implementa INpcDialogueDisplay — é um overlay independente do balão de
/// diálogo. "Show" não recebe um NpcController: encontra o player via a tag
/// "Player", para poder ser chamado tanto a partir de uma acção de diálogo
/// (Action_ShowFullscreenImage) como a partir do Diário no Menu de Pausa
/// (DiarySectionUI), onde não há nenhum NPC em contexto.
///
/// Configuração esperada (montar no Editor, normalmente dentro de um Canvas
/// que fique por cima do resto da UI):
/// - "panelRoot": GameObject raiz do overlay (fundo escurecido + imagem +
///   textos), desactivado por defeito.
/// - "imageElement": Image que mostra o sprite recebido.
/// - "titleText"/"descriptionText": TMP_Text opcionais — são desactivados
///   automaticamente se o respectivo texto vier vazio.
/// </summary>
public class FullscreenImageUI : MonoBehaviour
{
    public static FullscreenImageUI Instance { get; private set; }

    [Header("Referências")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private Image imageElement;
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private TMP_Text descriptionText;

    private PlayerInputRouter _input;
    private bool _confirmPressed;

    private void Awake()
    {
        Instance = this;

        if (panelRoot != null)
            panelRoot.SetActive(false);
    }

    private void OnDestroy()
    {
        if (Instance == this) Instance = null;
    }

    private void OnDisable()
    {
        Unsubscribe();
    }

    /// <summary>True enquanto o overlay estiver visível (ex: para outros sistemas evitarem reagir ao mesmo toque de Interagir).</summary>
    public bool IsOpen => panelRoot != null && panelRoot.activeSelf;

    /// <summary>
    /// Mostra "image" (com "title"/"description" opcionais) em ecrã inteiro,
    /// pausa o jogo, e só retorna depois de o jogador premir
    /// Confirmar/Interagir (teclado ou comando).
    /// </summary>
    public IEnumerator Show(Sprite image, string title, string description)
    {
        if (panelRoot == null)
        {
            Debug.LogWarning($"[{name}] FullscreenImageUI: 'panelRoot' não está atribuído.", this);
            yield break;
        }

        if (imageElement != null)
        {
            imageElement.sprite = image;
            imageElement.gameObject.SetActive(image != null);
        }

        if (titleText != null)
        {
            bool hasTitle = !string.IsNullOrEmpty(title);
            titleText.gameObject.SetActive(hasTitle);
            titleText.text = title;
        }

        if (descriptionText != null)
        {
            bool hasDescription = !string.IsNullOrEmpty(description);
            descriptionText.gameObject.SetActive(hasDescription);
            descriptionText.text = description;
        }

        // Só pausa/retoma se ainda não estava pausado (ex: reaberto a partir do
        // Diário, com o Menu de Pausa já a usar GamePauseUtil) — evita
        // despausar o jogo ao fechar a imagem nesse caso.
        bool didPause = !GamePauseUtil.IsPaused;
        if (didPause) GamePauseUtil.Pause();

        panelRoot.SetActive(true);
        Subscribe();

        _confirmPressed = false;
        while (!_confirmPressed)
            yield return null;

        Unsubscribe();
        panelRoot.SetActive(false);

        if (didPause) GamePauseUtil.Resume();
    }

    // ---------------- Input ----------------

    private void Subscribe()
    {
        Unsubscribe();

        var playerT = PlayerLocator.Find();
        if (playerT == null) return;

        _input = playerT.GetComponent<PlayerInputRouter>();
        if (_input != null)
            _input.InteractPressed += OnInteractPressed;
    }

    private void Unsubscribe()
    {
        if (_input != null)
            _input.InteractPressed -= OnInteractPressed;

        _input = null;
    }

    private void OnInteractPressed()
    {
        _confirmPressed = true;

        // Mesma mitigação do conflito de InteractPressed usada por
        // NpcDialogueBalloon: este toque pertence ao fecho da imagem em ecrã
        // inteiro, outros sistemas não devem reagir a ele.
        if (_input != null) _input.InteractConsumed = true;
    }
}
